using System;
using Xunit;
using FluentAssertions;
using Api.Models;

namespace Api.Tests
{
    public class OrderRequestTests
    {
        [Fact]
        public void OrderRequest_InvalidQuantity_ShouldAllowZeroAndNegativeValues()
        {
            // Arrange & Act
            var orderRequest1 = new OrderRequest { quantity = 0 };
            var orderRequest2 = new OrderRequest { quantity = -10 };

            // Assert
            orderRequest1.quantity.Should().Be(0);
            orderRequest2.quantity.Should().Be(-10);
        }

        [Fact]
        public void OrderRequest_StatusTransition_ShouldSupportAllDefinedStatuses()
        {
            // Arrange
            var orderRequest = new OrderRequest { status = OrderStatus.IN_PROGRESS };

            // Act & Assert
            orderRequest.status = OrderStatus.COMPLETED;
            orderRequest.status.Should().Be(OrderStatus.COMPLETED);

            orderRequest.status = OrderStatus.REJECTED;
            orderRequest.status.Should().Be(OrderStatus.REJECTED);
        }
    }
}

using System;
using System.Threading.Tasks;
using Api.Controllers;
using Api.Models;
using Confluent.Kafka;
using Microsoft.AspNetCore.Mvc;
using Moq;
using Xunit;
using FluentAssertions;
using Newtonsoft.Json;

namespace Api.Tests
{
    public class OrderControllerTests
    {
        private readonly Mock<ProducerConfig> _mockProducerConfig;
        private readonly Mock<ProducerWrapper> _mockProducerWrapper;

        public OrderControllerTests()
        {
            _mockProducerConfig = new Mock<ProducerConfig>();
            _mockProducerWrapper = new Mock<ProducerWrapper>(_mockProducerConfig.Object, "orderrequests");
        }

        [Fact]
        public async Task PostAsync_NullOrderRequest_ThrowsArgumentException()
        {
            // Arrange
            var controller = new OrderController(_mockProducerConfig.Object);

            // Act & Assert
            await Assert.ThrowsAsync<ArgumentException>(() => controller.PostAsync(null));
        }

        [Fact]
        public async Task PostAsync_EmptyOrderRequest_ReturnsBadRequest()
        {
            // Arrange
            var emptyOrderRequest = new OrderRequest();
            var controller = new OrderController(_mockProducerConfig.Object);

            // Act
            var result = await controller.PostAsync(emptyOrderRequest);

            // Assert
            result.Should().BeOfType<BadRequestObjectResult>();
        }
    }
